import React, { useState, useEffect, useRef, useCallback } from "react";
import api from "../api/axiosInstance";
import { getSensorByUser } from "../api/sensorsapi";

// ─── KPI API calls ──────────────────────────────────────────────────────────
const createKPI = (payload) =>
  api.post("/api/KPIs", {
    KPIName: payload.name,
    KPIFormula: payload.formula,
    Frequency: payload.frequency || "5min",
  });

const fetchKPIs        = ()        => api.get("/api/KPIs");
const fetchKPILatest   = (kpiId)   => api.get(`/api/KPIs/${kpiId}/latest`);
const softDeleteKPI    = (kpiId)   => api.delete(`/api/KPIs/${kpiId}`);
const restoreKPI       = (kpiId)   => api.patch(`/api/KPIs/${kpiId}/restore`);
const hardDeleteKPI    = (kpiId)   => api.delete(`/api/KPIs/${kpiId}/hard`);
const fetchDeletedKPIs = ()        => api.get("/api/KPIs/deleted");

// ─── Utilities ───────────────────────────────────────────────────────────────
const FREQ_MS = {
  "1min": 60_000, "5min": 300_000, "15min": 900_000,
  "30min": 1_800_000, "1hr": 3_600_000, "6hr": 21_600_000,
  "12hr": 43_200_000, "24hr": 86_400_000,
};
const freqToMs = (f) => FREQ_MS[f] ?? 300_000;

const formatCountdown = (secs) => {
  if (secs >= 3600) return `${Math.floor(secs / 3600)}h ${Math.floor((secs % 3600) / 60)}m`;
  if (secs >= 60)   return `${Math.floor(secs / 60)}m ${secs % 60}s`;
  return `${secs}s`;
};

const formatRelTime = (date) => {
  if (!date) return null;
  const diff = Math.round((Date.now() - date) / 1000);
  if (diff < 5)    return "just now";
  if (diff < 60)   return `${diff}s ago`;
  if (diff < 3600) return `${Math.floor(diff / 60)}m ago`;
  return `${Math.floor(diff / 3600)}h ago`;
};

const parseApiValue = (raw) => {
  const candidate =
    raw?.value ?? raw?.kpiValue ?? raw?.kpi_value ?? raw?.latestValue ??
    raw?.latest_value ?? raw?.result ??
    (Array.isArray(raw) && raw.length > 0
      ? (raw[0]?.value ?? raw[0]?.kpiValue ?? raw[0])
      : undefined) ??
    (typeof raw === "number" ? raw : null);
  if (candidate === null || candidate === undefined || isNaN(parseFloat(candidate))) return null;
  return Number(parseFloat(candidate).toFixed(2));
};

const evaluateFormula = (formulaStr, latestValues) => {
  if (!formulaStr?.trim()) return null;
  try {
    let expr = formulaStr.replace(/sensor_(\d+)/gi, (_, id) => {
      const v = latestValues[`sensor_${id}`] ?? latestValues[`sensor_${id}`.toUpperCase()];
      return v !== undefined ? v : "NaN";
    });
    expr = expr
      .replace(/AVG\(([^)]+)\)/gi, (_, a) => { const ns = a.split(",").map(Number).filter((n) => !isNaN(n)); return ns.length ? ns.reduce((s, v) => s + v, 0) / ns.length : 0; })
      .replace(/SUM\(([^)]+)\)/gi, (_, a) => a.split(",").map(Number).filter((n) => !isNaN(n)).reduce((s, v) => s + v, 0))
      .replace(/MAX\(([^)]+)\)/gi, (_, a) => Math.max(...a.split(",").map(Number).filter((n) => !isNaN(n))))
      .replace(/MIN\(([^)]+)\)/gi, (_, a) => Math.min(...a.split(",").map(Number).filter((n) => !isNaN(n))))
      .replace(/COUNT\(([^)]+)\)/gi, (_, a) => a.split(",").map(Number).filter((n) => !isNaN(n)).length);
    // eslint-disable-next-line no-new-func
    const r = Function('"use strict"; return (' + expr + ')')();
    return isNaN(r) || !isFinite(r) ? null : Number(r).toFixed(2);
  } catch { return null; }
};

const genTrendData = (baseVal, range) => {
  const counts = { "1h": 12, "6h": 24, "24h": 24, "7d": 7, "30d": 30 };
  const n = counts[range] || 24;
  const b = parseFloat(baseVal) || 50;
  return Array.from({ length: n }, () => +(b + (Math.random() - 0.5) * b * 0.15).toFixed(2));
};

const getTrendLabels = (range, count) => {
  const cfg = {
    "1h":  (i, n) => `-${(n - i) * 5}m`,
    "6h":  (i, n) => `-${(n - i) * 15}m`,
    "24h": (i, n) => `-${n - i}h`,
    "7d":  (i)    => ["Mon","Tue","Wed","Thu","Fri","Sat","Sun"][i % 7],
    "30d": (i)    => `Day ${i + 1}`,
  };
  const fn = cfg[range] ?? cfg["24h"];
  return Array.from({ length: count }, (_, i) => fn(i, count));
};

const COLOR_MAP   = ["#00c6ae","#0f8fd4","#7b5ea7","#f39c12","#e74c3c","#2ecc71","#e91e63"];
const ICON_MAP    = { availability:"bi-check2-circle", performance:"bi-speedometer2", quality:"bi-award", oee:"bi-graph-up", downtime:"bi-clock-history" };
const FX_FUNCS    = ["SUM","AVG","MAX","MIN","COUNT"];
const FREQUENCIES = ["1min","5min","15min","30min","1hr","6hr","12hr","24hr"];
const TREND_RANGES = ["1h","6h","24h","7d","30d"];
const MAX_HISTORY  = 120;

// ─── TrendChart ──────────────────────────────────────────────────────────────
const TrendChart = ({ data, color, labels }) => {
  const ref = useRef(null);
  useEffect(() => {
    const canvas = ref.current;
    if (!canvas || !data.length) return;
    const ctx = canvas.getContext("2d");
    const W = canvas.width, H = canvas.height;
    const PL = 42, PR = 10, PT = 12, PB = 28;
    const pw = W - PL - PR, ph = H - PT - PB;
    const min = Math.min(...data), max = Math.max(...data), rng = max - min || 1;
    ctx.clearRect(0, 0, W, H);
    ctx.font = "9px monospace"; ctx.textAlign = "right"; ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= 4; i++) {
      const val = min + (rng * i) / 4, y = PT + ph - (ph * i) / 4;
      ctx.strokeStyle = "rgba(150,150,150,0.15)"; ctx.lineWidth = 1;
      ctx.beginPath(); ctx.moveTo(PL, y); ctx.lineTo(PL + pw, y); ctx.stroke();
      ctx.fillText(val.toFixed(1), PL - 4, y + 3);
    }
    const xTicks = Math.min(5, data.length - 1);
    ctx.textAlign = "center"; ctx.fillStyle = "rgba(150,150,150,0.8)";
    for (let i = 0; i <= xTicks; i++) {
      const idx = Math.round((i / xTicks) * (data.length - 1));
      const x = PL + (idx / (data.length - 1)) * pw;
      ctx.fillText(labels[idx] || "", x, H - 6);
    }
    ctx.strokeStyle = "rgba(150,150,150,0.35)"; ctx.lineWidth = 1;
    ctx.beginPath(); ctx.moveTo(PL, PT); ctx.lineTo(PL, PT + ph); ctx.lineTo(PL + pw, PT + ph); ctx.stroke();
    ctx.beginPath();
    data.forEach((v, i) => {
      const x = PL + (i / (data.length - 1)) * pw;
      const y = PT + ph - ((v - min) / rng) * ph;
      i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
    });
    ctx.strokeStyle = color; ctx.lineWidth = 2.5; ctx.lineJoin = "round"; ctx.stroke();
    ctx.lineTo(PL + pw, PT + ph); ctx.lineTo(PL, PT + ph); ctx.closePath();
    ctx.fillStyle = color + "22"; ctx.fill();
    const lv = data[data.length - 1];
    const dx = PL + pw, dy = PT + ph - ((lv - min) / rng) * ph;
    ctx.beginPath(); ctx.arc(dx, dy, 4, 0, Math.PI * 2); ctx.fillStyle = color; ctx.fill();
  }, [data, color, labels]);
  return <canvas ref={ref} width={460} height={180} style={{ display:"block", width:"100%", height:180 }} />;
};

// ─── TrendPopup ──────────────────────────────────────────────────────────────
const TrendPopup = ({ kpi, onClose }) => {
  const [range, setRange] = useState("24h");
  const realHistory = kpi._history ?? [];
  const isReal = realHistory.length >= 3;
  const chartData = isReal ? realHistory.slice(-60) : genTrendData(kpi._liveVal, range);
  const labels    = getTrendLabels(range, chartData.length);
  const min = chartData.length ? Math.min(...chartData).toFixed(2) : "—";
  const max = chartData.length ? Math.max(...chartData).toFixed(2) : "—";
  const avg = chartData.length ? (chartData.reduce((s, v) => s + v, 0) / chartData.length).toFixed(2) : "—";

  return (
    <div style={{ position:"fixed", inset:0, zIndex:2000, background:"rgba(0,0,0,0.45)", display:"flex", alignItems:"center", justifyContent:"center", padding:16 }} onClick={onClose}>
      <div style={{ width:"100%", maxWidth:520, background:"var(--sb-white)", border:"1px solid var(--sb-border)", borderRadius:20, padding:24, boxShadow:"0 24px 64px rgba(0,0,0,0.18)" }} onClick={(e) => e.stopPropagation()}>
        <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginBottom:16 }}>
          <div style={{ display:"flex", alignItems:"center", gap:10 }}>
            <div style={{ width:32, height:32, borderRadius:8, background:kpi.color+"22", display:"flex", alignItems:"center", justifyContent:"center" }}>
              <i className={`bi ${kpi.icon}`} style={{ color:kpi.color, fontSize:"1rem" }} />
