            <div>
              <div style={{ fontSize:14, fontWeight:700, color:"var(--sb-text)" }}>{kpi.name}</div>
              <div style={{ fontSize:11, color:"var(--sb-muted)", display:"flex", alignItems:"center", gap:5 }}>
                Trend Analysis
                {isReal
                  ? <span style={{ background:"#00c6ae18", color:"#00c6ae", padding:"1px 7px", borderRadius:10, fontSize:10, fontWeight:700 }}>● Live -</span>
                  : <span style={{ background:"#f39c1218", color:"#f39c12", padding:"1px 7px", borderRadius:10, fontSize:10, fontWeight:700 }}>⚬ Accumulating…</span>
                }
