  );
};

// ─── KPI Card — Sensors-style layout ─────────────────────────────────────────
const KPICard = ({ kpi, lastRefreshed, isRefreshing, isAdmin, isOperator, onDelete, onShowTrend }) => {
  const [relTime, setRelTime]         = useState(() => formatRelTime(lastRefreshed));
  const [confirmDelete, setConfirmDelete] = useState(false);

  useEffect(() => {
    setRelTime(formatRelTime(lastRefreshed));
    const t = setInterval(() => setRelTime(formatRelTime(lastRefreshed)), 10_000);
    return () => clearInterval(t);
  }, [lastRefreshed]);

  const val       = kpi._liveVal;
  const noData    = val === null || val === undefined || !kpi.formula?.trim();
  const isDeleted = kpi.isDeleted;

  return (
    <div style={{
      background: "var(--sb-white)",
      borderRadius: 16,
      border: isDeleted ? "1.5px dashed var(--sb-border)" : "1px solid var(--sb-border)",
      padding: "20px 22px",
      display: "flex",
      flexDirection: "column",
      gap: 0,
      transition: "box-shadow 0.2s, transform 0.2s",
      opacity: isDeleted ? 0.65 : 1,
      position: "relative",
      overflow: "hidden",
    }}
      onMouseEnter={e => { if (!isDeleted) { e.currentTarget.style.boxShadow = "0 6px 24px rgba(0,0,0,0.09)"; e.currentTarget.style.transform = "translateY(-2px)"; } }}
      onMouseLeave={e => { e.currentTarget.style.boxShadow = ""; e.currentTarget.style.transform = ""; }}
    >
      {/* Top color bar */}
      <div style={{ position:"absolute", top:0, left:0, right:0, height:3, background: isDeleted ? "#ccc" : kpi.color, borderRadius:"16px 16px 0 0" }} />

      {/* Header row: name + badge */}
      <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between", marginBottom:12, marginTop:4 }}>
        <div>
          <h3 style={{ fontSize:"1.35rem", fontWeight:800, color:"var(--sb-text)", margin:0, letterSpacing:"-0.5px", fontFamily:"inherit" }}>{kpi.name}</h3>
        </div>
        <div style={{ display:"flex", alignItems:"center", gap:6 }}>
          {isRefreshing && !noData && !isDeleted && (
            <span style={{ width:6, height:6, borderRadius:"50%", background:"#00c6ae", animation:"pulseDot 0.8s infinite", display:"inline-block" }} />
          )}
          {isDeleted ? (
            <span style={{ display:"inline-flex", alignItems:"center", gap:4, fontSize:"0.73rem", fontWeight:700, padding:"3px 10px", borderRadius:50, background:"rgba(150,150,150,0.1)", color:"#999", border:"1px solid #ddd" }}>
              <i className="bi bi-trash3" style={{ fontSize:"0.65rem" }} />Deleted
            </span>
          ) : noData ? (
            <span style={{ display:"inline-flex", alignItems:"center", gap:4, fontSize:"0.73rem", fontWeight:700, padding:"3px 10px", borderRadius:50, background:"rgba(229,62,62,0.09)", color:"#e53e3e", border:"1px solid rgba(229,62,62,0.2)" }}>
              <span style={{ width:6, height:6, borderRadius:"50%", background:"#e53e3e", display:"inline-block" }} />No Data
            </span>
          ) : (
            <span style={{ display:"inline-flex", alignItems:"center", gap:4, fontSize:"0.73rem", fontWeight:700, padding:"3px 10px", borderRadius:50, background:"rgba(0,198,174,0.09)", color:"#00c6ae", border:"1px solid rgba(0,198,174,0.2)" }}>
              <span style={{ width:6, height:6, borderRadius:"50%", background:"#00c6ae", display:"inline-block", animation:"pulseDot 2s infinite" }} />Active
            </span>
          )}
        </div>
      </div>

      {/* Info rows — mirror sensor card style */}
      <div style={{ display:"flex", flexDirection:"column", gap:7, marginBottom:16 }}>
        {/* Live value */}
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <i className="bi bi-graph-up" style={{ color: isDeleted ? "#aaa" : kpi.color, fontSize:"0.82rem", width:14, textAlign:"center" }} />
          {noData || isDeleted ? (
            <span style={{ fontSize:"0.83rem", color:"var(--sb-muted)", fontStyle:"italic" }}>
              {!kpi.formula?.trim() ? "No formula configured" : "Unable to compute value"}
            </span>
          ) : (
            <span style={{ fontSize:"0.83rem", color:"var(--sb-text)", fontWeight:600 }}>
              {val} {kpi.unit && <span style={{ color:"var(--sb-muted)", fontWeight:400 }}>{kpi.unit}</span>}
            </span>
          )}
        </div>

        {/* Formula */}
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <i className="bi bi-code-slash" style={{ color:"var(--sb-muted)", fontSize:"0.82rem", width:14, textAlign:"center" }} />
          <span style={{ fontSize:"0.83rem", color:"var(--sb-muted)", fontFamily:"monospace", overflow:"hidden", textOverflow:"ellipsis", whiteSpace:"nowrap", maxWidth:200 }} title={kpi.formula || "No formula"}>
            {kpi.formula ? (kpi.formula.length > 28 ? kpi.formula.slice(0, 28) + "…" : kpi.formula) : "—"}
          </span>
        </div>

        {/* Frequency */}
        <div style={{ display:"flex", alignItems:"center", gap:8 }}>
          <i className="bi bi-clock-history" style={{ color:"var(--sb-muted)", fontSize:"0.82rem", width:14, textAlign:"center" }} />
          <span style={{ fontSize:"0.83rem", color:"var(--sb-muted)" }}>Every {kpi.frequency}</span>
        </div>

        {/* Last updated */}
        {!noData && !isDeleted && relTime && (
          <div style={{ display:"flex", alignItems:"center", gap:8 }}>
            <i className="bi bi-calendar3" style={{ color:"var(--sb-muted)", fontSize:"0.82rem", width:14, textAlign:"center" }} />
            <span style={{ fontSize:"0.83rem", color:"var(--sb-muted)" }}>
